import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

const changelogPath = path.join(process.cwd(), "CHANGELOG.md");
const historyPath = path.join(process.cwd(), "docs", "release", "history.md");
const changelog = await readFile(changelogPath, "utf8");
const sections = extractChangelogSections(changelog);

validateChangelog(sections);

await mkdir(path.dirname(historyPath), { recursive: true });
await writeFile(
  historyPath,
  [
    "# Release History",
    "",
    "<!-- This file is generated by scripts/generate-release-history.mjs. -->",
    "",
    "This page is generated from the repository changelog so release documentation stays aligned with published versions.",
    "",
    sections,
    "",
  ].join("\n"),
);

function extractChangelogSections(content) {
  const normalized = content.replace(/\r\n/g, "\n").trim();
  if (!normalized.startsWith("# Changelog\n")) {
    throw new Error("CHANGELOG.md must start with '# Changelog'.");
  }
  return normalized.replace(/^# Changelog\n+/, "").trim();
}

function validateChangelog(content) {
  const sectionHeadings = [...content.matchAll(/^## \[?([^\]\n]+)\]?(?:[^\n]*)$/gm)].map((match) => match[1]);
  if (sectionHeadings[0] !== "Unreleased") {
    throw new Error("CHANGELOG.md must keep the Unreleased section first.");
  }

  const versions = sectionHeadings.filter((heading) => /^\d+\.\d+\.\d+$/.test(heading));
  if (versions.length === 0) {
    throw new Error("CHANGELOG.md must include at least one dated semver release section.");
  }

  for (const version of versions) {
    const headingPattern = new RegExp(
      `^## \\[?${escapeRegExp(version)}\\]?(?:[^\\n]*)\\(?(\\d{4}-\\d{2}-\\d{2})\\)?$`,
      "m",
    );
    if (!headingPattern.test(content)) {
      throw new Error(`CHANGELOG.md release ${version} must include a YYYY-MM-DD date.`);
    }
  }
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}
